import { ExternalTokenizer } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { LogicalOperator } from '../parser.terms.js';

const { EOF, SPACE, OPENING_BRACKET, CLOSING_BRACKET, DOUBLEQUOTE, BACKSLASH } =
  characterCodes;

// Valid input after a logical operator. Every other input will result in the
// token not being accepted.
const validAfterLogicalOperator = [
  OPENING_BRACKET,
  CLOSING_BRACKET,
  DOUBLEQUOTE,
  BACKSLASH,
  SPACE,
  EOF,
];

/** @internal */
export const logicalOperatorTokenizer = new ExternalTokenizer((inputStream) => {
  const char = String.fromCharCode(inputStream.next).toLowerCase();
  let tokenOffset = 0;

  // Only if the current character is an 'a' (and) or 'o' (or), the token may be a valid LogicalOperator.
  switch (char) {
    case 'a':
      // Input stream matches 'and'.
      if (
        // TODO: switch to match sequence.
        String.fromCharCode(inputStream.peek(1)).toLowerCase() === 'n' &&
        String.fromCharCode(inputStream.peek(2)).toLowerCase() === 'd'
      ) {
        tokenOffset = 3;
      }
      break;
    case 'o':
      // Input stream matches 'or'.
      // TODO: switch to match sequence.
      if (String.fromCharCode(inputStream.peek(1)).toLowerCase() === 'r') {
        tokenOffset = 2;
      }
      break;
    default:
      // Early exit. Input doesn't match a LogicalOperator.
      return;
  }

  // Advance to the last character of the token.
  inputStream.advance(tokenOffset);

  // Check, if the next character is a valid character after a LogicalOperator.
  // If yes, accept the token, excluding the next character to only match the exact token.
  if (validAfterLogicalOperator.includes(inputStream.next)) {
    inputStream.acceptToken(LogicalOperator);
  }
});
